```typescript
export type PrescriptionState =
  | { status: "none" }
  | { status: "active"; id: string; drug: string; refillsLeft: number }
  | { status: "cancelled"; id: string; reason: string };

export type PrescriptionCommand =
  | { type: "prescribe"; id: string; drug: string; refills: number }
  | { type: "refill"; at: string }
  | { type: "cancel"; reason: string };

export type PrescriptionEvent =
  | { type: "PrescriptionWritten"; id: string; drug: string; refills: number }
  | { type: "PrescriptionRefilled"; at: string }
  | { type: "PrescriptionCancelled"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const prescriptionDecider: Decider<PrescriptionCommand, PrescriptionEvent, PrescriptionState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "prescribe":
        if (s.status !== "none") throw new DomainError("EXISTS");
        if (c.refills < 0) throw new DomainError("REFILLS_NEGATIVE");
        return [{ type: "PrescriptionWritten", id: c.id, drug: c.drug, refills: c.refills }];
      case "refill":
        if (s.status === "cancelled") throw new DomainError("CANCELLED");
        if (s.status === "none") throw new DomainError("NOT_WRITTEN");
        if (s.refillsLeft <= 0) throw new DomainError("NO_REFILLS");
        return [{ type: "PrescriptionRefilled", at: c.at }];
      case "cancel":
        if (s.status === "cancelled") throw new DomainError("ALREADY_CANCELLED");
        return [{ type: "PrescriptionCancelled", reason: c.reason }];
      default: {
        const _never: never = c;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "PrescriptionWritten":
        return { status: "active", id: e.id, drug: e.drug, refillsLeft: e.refills };
      case "PrescriptionRefilled":
        if (s.status !== "active") return s;
        return { ...s, refillsLeft: s.refillsLeft - 1 };
      case "PrescriptionCancelled":
        if (s.status === "none") return s;
        return { status: "cancelled", id: s.status === "active" ? s.id : "", reason: e.reason };
      default: {
        const _never: never = e;
        return s;
      }
    }
  },
};
```

A Decider bundles an aggregate's pure decision logic: an initial state, a `decide(command, state)` that returns events or throws on invariant violation, and an `evolve(state, event)` that folds events back into state. No I/O lives inside; side effects stay at the edge.

```typescript
export type LabOrderState =
  | { status: "none" }
  | { status: "placed"; id: string; panel: string }
  | { status: "collected"; id: string; panel: string; at: string }
  | { status: "resulted"; id: string; panel: string; values: Record<string, number> }
  | { status: "cancelled"; id: string; reason: string };

export type LabOrderCommand =
  | { type: "place"; id: string; panel: string }
  | { type: "collect"; at: string }
  | { type: "result"; values: Record<string, number> }
  | { type: "cancel"; reason: string };

export type LabOrderEvent =
  | { type: "LabOrderPlaced"; id: string; panel: string }
  | { type: "SpecimenCollected"; at: string }
  | { type: "LabOrderResulted"; values: Record<string, number> }
  | { type: "LabOrderCancelled"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const labOrderDecider: Decider<LabOrderCommand, LabOrderEvent, LabOrderState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "place":
        if (s.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "LabOrderPlaced", id: c.id, panel: c.panel }];
      case "collect":
        if (s.status !== "placed") throw new DomainError("NOT_PLACED");
        return [{ type: "SpecimenCollected", at: c.at }];
      case "result":
        if (s.status !== "collected") throw new DomainError("NOT_COLLECTED");
        return [{ type: "LabOrderResulted", values: c.values }];
      case "cancel":
        if (s.status === "resulted" || s.status === "cancelled") throw new DomainError("FINAL");
        return [{ type: "LabOrderCancelled", reason: c.reason }];
      default: {
        const _never: never = c;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "LabOrderPlaced":
        return { status: "placed", id: e.id, panel: e.panel };
      case "SpecimenCollected":
        if (s.status !== "placed") return s;
        return { status: "collected", id: s.id, panel: s.panel, at: e.at };
      case "LabOrderResulted":
        if (s.status !== "collected") return s;
        return { status: "resulted", id: s.id, panel: s.panel, values: e.values };
      case "LabOrderCancelled":
        if (s.status === "none") return s;
        return { status: "cancelled", id: "id" in s ? s.id : "", reason: e.reason };
      default: {
        const _never: never = e;
        return s;
      }
    }
  },
};
