export type VisitRecordState =
  | { status: "none" }
  | { status: "open"; id: string; patientId: string; notes: string[] }
  | { status: "signed"; id: string; patientId: string; notes: string[]; signedBy: string; at: string }
  | { status: "amended"; id: string; patientId: string; notes: string[]; amendedAt: string };

export type VisitRecordCommand =
  | { type: "start"; id: string; patientId: string }
  | { type: "addNote"; note: string }
  | { type: "sign"; by: string; at: string }
  | { type: "amend"; note: string; at: string };

export type VisitRecordEvent =
  | { type: "VisitRecordStarted"; id: string; patientId: string }
  | { type: "NoteAppended"; note: string }
  | { type: "VisitRecordSigned"; by: string; at: string }
  | { type: "VisitRecordAmended"; note: string; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const visitRecordDecider: Decider<VisitRecordCommand, VisitRecordEvent, VisitRecordState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "start":
        if (s.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "VisitRecordStarted", id: c.id, patientId: c.patientId }];
      case "addNote":
        if (s.status !== "open") throw new DomainError("NOT_OPEN");
        if (!c.note.trim()) throw new DomainError("NOTE_EMPTY");
        return [{ type: "NoteAppended", note: c.note }];
      case "sign":
        if (s.status !== "open") throw new DomainError("NOT_OPEN");
        if (s.notes.length === 0) throw new DomainError("NO_NOTES");
        return [{ type: "VisitRecordSigned", by: c.by, at: c.at }];
      case "amend":
        if (s.status !== "signed") throw new DomainError("NOT_SIGNED");
        return [{ type: "VisitRecordAmended", note: c.note, at: c.at }];
      default: {
        const _never: never = c;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "VisitRecordStarted":
        return { status: "open", id: e.id, patientId: e.patientId, notes: [] };
      case "NoteAppended":
        if (s.status !== "open") return s;
        return { ...s, notes: [...s.notes, e.note] };
      case "VisitRecordSigned":
        if (s.status !== "open") return s;
        return { status: "signed", id: s.id, patientId: s.patientId, notes: s.notes, signedBy: e.by, at: e.at };
      case "VisitRecordAmended":
        if (s.status !== "signed") return s;
        return { status: "amended", id: s.id, patientId: s.patientId, notes: [...s.notes, e.note], amendedAt: e.at };
      default: {
        const _never: never = e;
        return s;
      }
    }
  },
};
