export type TreatmentPlanState =
  | { status: "none" }
  | { status: "draft"; id: string; patientId: string; steps: string[] }
  | { status: "approved"; id: string; patientId: string; steps: string[]; by: string }
  | { status: "active"; id: string; patientId: string; steps: string[]; startedAt: string }
  | { status: "completed"; id: string; at: string };

export type TreatmentPlanCommand =
  | { type: "draft"; id: string; patientId: string; steps: string[] }
  | { type: "approve"; by: string }
  | { type: "activate"; at: string }
  | { type: "complete"; at: string };

export type TreatmentPlanEvent =
  | { type: "TreatmentPlanDrafted"; id: string; patientId: string; steps: string[] }
  | { type: "TreatmentPlanApproved"; by: string }
  | { type: "TreatmentPlanActivated"; at: string }
  | { type: "TreatmentPlanCompleted"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const treatmentPlanDecider: Decider<TreatmentPlanCommand, TreatmentPlanEvent, TreatmentPlanState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "draft":
        if (s.status !== "none") throw new DomainError("EXISTS");
        if (c.steps.length === 0) throw new DomainError("NO_STEPS");
        return [{ type: "TreatmentPlanDrafted", id: c.id, patientId: c.patientId, steps: c.steps }];
      case "approve":
        if (s.status !== "draft") throw new DomainError("NOT_DRAFT");
        return [{ type: "TreatmentPlanApproved", by: c.by }];
      case "activate":
        if (s.status !== "approved") throw new DomainError("NOT_APPROVED");
        return [{ type: "TreatmentPlanActivated", at: c.at }];
      case "complete":
        if (s.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "TreatmentPlanCompleted", at: c.at }];
      default: {
        const _never: never = c;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "TreatmentPlanDrafted":
        return { status: "draft", id: e.id, patientId: e.patientId, steps: e.steps };
      case "TreatmentPlanApproved":
        if (s.status !== "draft") return s;
        return { status: "approved", id: s.id, patientId: s.patientId, steps: s.steps, by: e.by };
      case "TreatmentPlanActivated":
        if (s.status !== "approved") return s;
        return { status: "active", id: s.id, patientId: s.patientId, steps: s.steps, startedAt: e.at };
      case "TreatmentPlanCompleted":
        if (s.status !== "active") return s;
        return { status: "completed", id: s.id, at: e.at };
      default: {
        const _never: never = e;
        return s;
      }
    }
  },
};
