```typescript
export type PatientEvent =
  | { type: "PatientRegistered"; id: string; mrn: string; name: string }
  | { type: "PatientAdmitted"; id: string; ward: string; at: string }
  | { type: "PatientDischarged"; id: string; at: string };

export interface AdmissionRow {
  readonly id: string;
  readonly mrn: string;
  readonly name: string;
  readonly ward: string | null;
  readonly admittedAt: string | null;
  readonly dischargedAt: string | null;
}

export interface AdmissionsView {
  readonly rows: Record<string, AdmissionRow>;
}

export const emptyView: AdmissionsView = { rows: {} };

export function project(view: AdmissionsView, event: PatientEvent): AdmissionsView {
  switch (event.type) {
    case "PatientRegistered":
      return {
        rows: {
          ...view.rows,
          [event.id]: { id: event.id, mrn: event.mrn, name: event.name, ward: null, admittedAt: null, dischargedAt: null },
        },
      };
    case "PatientAdmitted": {
      const row = view.rows[event.id];
      if (!row) return view;
      return { rows: { ...view.rows, [event.id]: { ...row, ward: event.ward, admittedAt: event.at, dischargedAt: null } } };
    }
    case "PatientDischarged": {
      const row = view.rows[event.id];
      if (!row) return view;
      return { rows: { ...view.rows, [event.id]: { ...row, dischargedAt: event.at } } };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
