```typescript
export type FormularyEvent =
  | { type: "DrugListed"; code: string; name: string; tier: number }
  | { type: "DrugDelisted"; code: string; at: string }
  | { type: "TierChanged"; code: string; tier: number }
  | { type: "FormularyReviewed"; reviewer: string; at: string };

export interface DrugRow {
  readonly code: string;
  readonly name: string;
  readonly tier: number;
  readonly active: boolean;
}

export interface FormularyView {
  readonly drugs: Record<string, DrugRow>;
}

export const emptyView: FormularyView = { drugs: {} };

export function project(view: FormularyView, event: FormularyEvent): FormularyView {
  switch (event.type) {
    case "DrugListed":
      return { drugs: { ...view.drugs, [event.code]: { code: event.code, name: event.name, tier: event.tier, active: true } } };
    case "DrugDelisted": {
      const row = view.drugs[event.code];
      if (!row) return view;
      return { drugs: { ...view.drugs, [event.code]: { ...row, active: false } } };
    }
    case "TierChanged": {
      const row = view.drugs[event.code];
      if (!row) return view;
      return { drugs: { ...view.drugs, [event.code]: { ...row, tier: event.tier } } };
    }
    case "FormularyReviewed":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export function aggregateStream(events: FormularyEvent[]): FormularyView {
  return events.reduce(project, emptyView);
}
```

A projection reduces events to a query-optimised read model, denormalised for the view's needs. `evolve` rebuilds the aggregate's write-side state; a projection keeps the read side eventually consistent and can ignore events it does not care about.

```typescript
export type ClinicalTrialEvent =
  | { type: "TrialOpened"; id: string; title: string; capacity: number }
  | { type: "ParticipantEnrolled"; id: string; participantId: string }
  | { type: "ParticipantWithdrawn"; id: string; participantId: string }
  | { type: "TrialClosed"; id: string; at: string };

export interface TrialRow {
  readonly id: string;
  readonly title: string;
  readonly capacity: number;
  readonly enrolled: number;
  readonly closed: boolean;
}

export interface TrialView {
  readonly trials: Record<string, TrialRow>;
}

export const emptyView: TrialView = { trials: {} };

export function project(view: TrialView, event: ClinicalTrialEvent): TrialView {
  switch (event.type) {
    case "TrialOpened":
      return { trials: { ...view.trials, [event.id]: { id: event.id, title: event.title, capacity: event.capacity, enrolled: 0, closed: false } } };
    case "ParticipantEnrolled": {
      const row = view.trials[event.id];
      if (!row) return view;
      return { trials: { ...view.trials, [event.id]: { ...row, enrolled: row.enrolled + 1 } } };
    }
    case "ParticipantWithdrawn": {
      const row = view.trials[event.id];
      if (!row) return view;
      return { trials: { ...view.trials, [event.id]: { ...row, enrolled: Math.max(0, row.enrolled - 1) } } };
    }
    case "TrialClosed": {
      const row = view.trials[event.id];
      if (!row) return view;
      return { trials: { ...view.trials, [event.id]: { ...row, closed: true } } };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
