```typescript
export interface PrescriptionStateV3 {
  readonly id: string;
  readonly drug: string;
  readonly refillsLeft: number;
  readonly lastRefillAt: string | null;
  readonly prescriberId: string;
}

interface PrescriptionStateV2 {
  readonly id: string;
  readonly drug: string;
  readonly refillsLeft: number;
  readonly lastRefillAt: string | null;
}

interface PrescriptionStateV1 {
  readonly id: string;
  readonly drug: string;
  readonly refills: number;
}

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export const CURRENT_VERSION = 3 as const;

function v1Tov2(s: PrescriptionStateV1): PrescriptionStateV2 {
  return { id: s.id, drug: s.drug, refillsLeft: s.refills, lastRefillAt: null };
}

function v2Tov3(s: PrescriptionStateV2): PrescriptionStateV3 {
  return { ...s, prescriberId: "unknown" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<PrescriptionStateV3> {
  let version = snap.version;
  let state = snap.state;
  if (version === 1) {
    state = v1Tov2(state as PrescriptionStateV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as PrescriptionStateV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new Error(`Unknown snapshot version ${version}`);
  return { version: CURRENT_VERSION, state: state as PrescriptionStateV3 };
}
