  readonly protocolVersion: string;
}

export type ClinicalTrialEvent =
  | { type: "ParticipantEnrolled"; id: string }
  | { type: "ParticipantWithdrawn"; id: string }
  | { type: "TrialClosed" };

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export const CURRENT_VERSION = 3 as const;

interface V1 { id: string; title: string; capacity: number; enrolled: number }
interface V2 { id: string; title: string; capacity: number; enrolled: number; closed: boolean }

function v1Tov2(s: V1): V2 { return { ...s, closed: false }; }
function v2Tov3(s: V2): ClinicalTrialState { return { ...s, protocolVersion: "1.0" }; }

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<ClinicalTrialState> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) { state = v1Tov2(state as V1); version = 2; }
  if (version === 2) { state = v2Tov3(state as V2); version = 3; }
  if (version !== CURRENT_VERSION) throw new Error(`Unknown version ${version}`);
  return { version: CURRENT_VERSION, state: state as ClinicalTrialState };
}

export function evolve(state: ClinicalTrialState, event: ClinicalTrialEvent): ClinicalTrialState {
  switch (event.type) {
    case "ParticipantEnrolled":
      return { ...state, enrolled: state.enrolled + 1 };
    case "ParticipantWithdrawn":
      return { ...state, enrolled: Math.max(0, state.enrolled - 1) };
    case "TrialClosed":
      return { ...state, closed: true };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function loadSnapshot(snap: Snapshot<unknown>, tail: ClinicalTrialEvent[]): ClinicalTrialState {
  const current = upgradeSnapshot(snap);
  return tail.reduce(evolve, current.state);
}
