```typescript
export type ExpectedRevision = bigint | "no_stream" | "any";

export interface ReadResult<E> { readonly revision: bigint; readonly events: E[] }
export interface AppendResult { readonly nextRevision: bigint }
export interface ConflictSignal { readonly kind: "conflict"; readonly actual: bigint }

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadResult<E>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<AppendResult | ConflictSignal>;
}

export class ConcurrencyConflict extends Error {
  constructor(readonly actual: bigint) { super(`conflict@${actual}`); this.name = "ConcurrencyConflict"; }
}

export async function appendWithRetry<E, S>(
  store: EventStore<E>,
  stream: string,
  evolve: (s: S, e: E) => S,
  initial: S,
  decide: (state: S) => E[],
  maxAttempts = 3,
): Promise<bigint> {
  let attempt = 0;
  while (attempt < maxAttempts) {
    attempt++;
    const current = await store.readStream(stream);
    const state = current.events.reduce(evolve, initial);
    const events = decide(state);
    const expectedRevision: ExpectedRevision = current.events.length === 0 ? "no_stream" : current.revision;
    const result = await store.appendToStream(stream, events, { expectedRevision });
    if ("kind" in result && result.kind === "conflict") {
      if (attempt >= maxAttempts) throw new ConcurrencyConflict(result.actual);
      continue;
    }
    return (result as AppendResult).nextRevision;
  }
  throw new ConcurrencyConflict(-1n);
}
