export type ExpectedRevision = bigint | "no_stream" | "any";

export interface ReadResult<E> { readonly revision: bigint; readonly events: E[] }
export interface AppendResult { readonly nextRevision: bigint }

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadResult<E>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<AppendResult>;
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export async function handleCommand<C, E, S>(
  decider: Decider<C, E, S>,
  store: EventStore<E>,
  streamName: string,
  command: C,
): Promise<bigint> {
  const read = await store.readStream(streamName);
  const state = read.events.reduce((s, e) => decider.evolve(s, e), decider.initialState);
  const events = decider.decide(command, state);
  const expectedRevision: ExpectedRevision = read.events.length === 0 ? "no_stream" : read.revision;
  const result = await store.appendToStream(streamName, events, { expectedRevision });
  return result.nextRevision;
}

