export type FormularyEvent =
  | { type: "DrugListed"; code: string; name: string }
  | { type: "DrugDelisted"; code: string };

export interface FormularyRow { readonly code: string; readonly name: string; readonly active: boolean }
export interface FormularyView { readonly drugs: Record<string, FormularyRow> }
export const emptyView: FormularyView = { drugs: {} };

export function project(view: FormularyView, event: FormularyEvent): FormularyView {
  switch (event.type) {
    case "DrugListed":
      return { drugs: { ...view.drugs, [event.code]: { code: event.code, name: event.name, active: true } } };
    case "DrugDelisted": {
      const row = view.drugs[event.code];
      if (!row) return view;
      return { drugs: { ...view.drugs, [event.code]: { ...row, active: false } } };
    }
    default: { const _never: never = event; return view; }
  }
}

export async function runSubscription(
  name: string,
  stream: string,
  store: EventStore<FormularyEvent>,
  checkpoints: CheckpointStore,
  persist: (view: FormularyView) => Promise<void>,
): Promise<void> {
  const start = (await checkpoints.read(name)) ?? 0n;
  let view: FormularyView = emptyView;
  async function loop(): Promise<void> {
    for await (const stored of store.readFromStream(stream, start)) {
      view = project(view, stored.event);
      await persist(view);
      await checkpoints.write(name, stored.position);
    }
  }
  await loop();
}
