export type ExpectedRevision = bigint | "no_stream" | "any";

export interface ReadResult<E> { readonly revision: bigint; readonly events: E[] }
export interface AppendResult { readonly nextRevision: bigint }
export interface EventStore<E> {
  readStream(stream: string): Promise<ReadResult<E>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<AppendResult>;
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export type TreatmentPlanCommand = { type: "draft"; id: string; steps: string[] } | { type: "approve"; by: string };
export type TreatmentPlanEvent = { type: "TreatmentPlanDrafted"; id: string; steps: string[] } | { type: "TreatmentPlanApproved"; by: string };
export type TreatmentPlanState = { status: "none" } | { status: "draft"; id: string; steps: string[] } | { status: "approved"; id: string; by: string };

export const treatmentDecider: Decider<TreatmentPlanCommand, TreatmentPlanEvent, TreatmentPlanState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "draft":
        if (s.status !== "none") throw new Error("EXISTS");
        return [{ type: "TreatmentPlanDrafted", id: c.id, steps: c.steps }];
      case "approve":
        if (s.status !== "draft") throw new Error("NOT_DRAFT");
        return [{ type: "TreatmentPlanApproved", by: c.by }];
      default: { const _never: never = c; throw new Error("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "TreatmentPlanDrafted": return { status: "draft", id: e.id, steps: e.steps };
      case "TreatmentPlanApproved":
        if (s.status !== "draft") return s;
        return { status: "approved", id: s.id, by: e.by };
      default: { const _never: never = e; return s; }
    }
  },
};

export interface TreatmentView { readonly id: string; readonly status: string; readonly steps: string[] }
export interface ReadStore { load(id: string): Promise<TreatmentView | null> }

// Read store is eventually consistent with the event store; a projection worker
// subscribes to events and updates it asynchronously.
export async function handleCommand(
  command: TreatmentPlanCommand,
  ctx: { streamName: string; eventStore: EventStore<TreatmentPlanEvent> },
): Promise<void> {
  const read = await ctx.eventStore.readStream(ctx.streamName);
  const state = read.events.reduce((s, e) => treatmentDecider.evolve(s, e), treatmentDecider.initialState);
  const events = treatmentDecider.decide(command, state);
  const expectedRevision: ExpectedRevision = read.events.length === 0 ? "no_stream" : read.revision;
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision });
}

export async function queryView(id: string, readStore: ReadStore): Promise<TreatmentView | null> {
  return readStore.load(id);
}
```

CQRS routes writes through a Decider + `appendToStream` (the aggregate state is reconstructed on each command); reads go to a denormalised projection. They share the event DU but hold independent state: the write side's invariants belong to the aggregate, the read side's shape belongs to the view.

```typescript
export type ExpectedRevision = bigint | "no_stream" | "any";
export interface ReadResult<E> { readonly revision: bigint; readonly events: E[] }
export interface AppendResult { readonly nextRevision: bigint }
export interface EventStore<E> {
  readStream(stream: string): Promise<ReadResult<E>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<AppendResult>;
}

export type ProcedureCommand = { type: "schedule"; id: string; name: string } | { type: "perform"; at: string };
export type ProcedureEvent = { type: "ProcedureScheduled"; id: string; name: string } | { type: "ProcedurePerformed"; at: string };
type WriteState = { status: "none" } | { status: "scheduled"; id: string; name: string } | { status: "done"; id: string };

const initial: WriteState = { status: "none" };
function evolve(s: WriteState, e: ProcedureEvent): WriteState {
  switch (e.type) {
    case "ProcedureScheduled": return { status: "scheduled", id: e.id, name: e.name };
    case "ProcedurePerformed":
      if (s.status !== "scheduled") return s;
      return { status: "done", id: s.id };
    default: { const _never: never = e; return s; }
  }
}
function decide(c: ProcedureCommand, s: WriteState): ProcedureEvent[] {
  switch (c.type) {
    case "schedule":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "ProcedureScheduled", id: c.id, name: c.name }];
    case "perform":
      if (s.status !== "scheduled") throw new Error("NOT_SCHEDULED");
      return [{ type: "ProcedurePerformed", at: c.at }];
    default: { const _never: never = c; throw new Error("UNKNOWN"); }
  }
}

export interface ProcedureRow { readonly id: string; readonly name: string; readonly done: boolean }
export interface ReadStore { load(id: string): Promise<ProcedureRow | null> }

export async function handleCommand(command: ProcedureCommand, ctx: { streamName: string; eventStore: EventStore<ProcedureEvent> }): Promise<void> {
  const r = await ctx.eventStore.readStream(ctx.streamName);
  const s = r.events.reduce(evolve, initial);
  const events = decide(command, s);
  const expectedRevision: ExpectedRevision = r.events.length === 0 ? "no_stream" : r.revision;
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision });
}

export async function queryView(id: string, readStore: ReadStore): Promise<ProcedureRow | null> {
  return readStore.load(id);
}
