import { Effect, Schedule } from "effect";

export type ExpectedRevision = bigint | "no_stream" | "any";
export interface ReadResult<E> { readonly revision: bigint; readonly events: E[] }
export interface AppendResult { readonly nextRevision: bigint }
export interface ConflictSignal { readonly kind: "conflict"; readonly actual: bigint }
export interface EventStore<E> {
  readStream(stream: string): Promise<ReadResult<E>>;
  appendToStream(stream: string, events: E[], opts: { expectedRevision: ExpectedRevision }): Promise<AppendResult | ConflictSignal>;
}

export type PatientCommand = { type: "register"; id: string; mrn: string };
export type PatientEvent = { type: "PatientRegistered"; id: string; mrn: string };
export type PatientState = { status: "none" } | { status: "registered"; id: string; mrn: string };

const initial: PatientState = { status: "none" };
function evolve(s: PatientState, e: PatientEvent): PatientState {
  switch (e.type) {
    case "PatientRegistered": return { status: "registered", id: e.id, mrn: e.mrn };
    default: { const _never: never = e.type; return s; }
  }
}
function decide(c: PatientCommand, s: PatientState): PatientEvent[] {
  if (s.status !== "none") throw new Error("EXISTS");
  return [{ type: "PatientRegistered", id: c.id, mrn: c.mrn }];
}

export class ConcurrencyConflict extends Error {
  readonly _tag = "ConcurrencyConflict" as const;
  constructor(readonly actual: bigint) { super("conflict"); }
}

export const handle = (store: EventStore<PatientEvent>, stream: string, command: PatientCommand) =>
  Effect.gen(function* () {
    const read = yield* Effect.tryPromise({ try: () => store.readStream(stream), catch: (e) => new Error(String(e)) });
    const state = read.events.reduce(evolve, initial);
    const events = decide(command, state);
    const expectedRevision: ExpectedRevision = read.events.length === 0 ? "no_stream" : read.revision;
    const result = yield* Effect.tryPromise({
      try: () => store.appendToStream(stream, events, { expectedRevision }),
      catch: (e) => new Error(String(e)),
    });
    if ("kind" in result && result.kind === "conflict") {
      return yield* Effect.fail(new ConcurrencyConflict(result.actual));
    }
    return (result as AppendResult).nextRevision;
  }).pipe(Effect.retry(Schedule.recurs(3)));
